@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var isCompleted = stepIndex < CurrentStep;
        var isCurrent = stepIndex == CurrentStep;
        var isFuture = stepIndex > CurrentStep;

        <div class="step-item text-center flex-fill position-relative @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
             role="button"
             @onclick="() => OnStepClicked(stepIndex)">
            <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : isCurrent ? "fw-bold text-primary" : "text-success")">
                @StepNames[stepIndex]
            </small>
            @if (stepIndex < StepNames.Length - 1)
            {
                <div class="step-connector @(isCompleted ? "bg-success" : "bg-light")"></div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigateToStep { get; set; }

    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(step);
        }
    }
}

.step-indicator .step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    transition: all 0.2s;
}

.step-indicator .step-item {
    cursor: default;
    position: relative;
}

.step-indicator .step-item.completed {
    cursor: pointer;
}

.step-indicator .step-item.dimmed {
    opacity: 0.5;
}

.step-connector {
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    right: calc(-50% + 22px);
    height: 3px;
    z-index: 0;
}

@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control @ValidationClass(nameof(FullName))" @bind="FullName" />
    @if (_errors.ContainsKey(nameof(FullName)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(FullName)]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @ValidationClass(nameof(Email))" @bind="Email" />
    @if (_errors.ContainsKey(nameof(Email)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Email)]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control @ValidationClass(nameof(Phone))" @bind="Phone" />
    @if (_errors.ContainsKey(nameof(Phone)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Phone)]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control @ValidationClass(nameof(Address))" @bind="Address" rows="2"></textarea>
    @if (_errors.ContainsKey(nameof(Address)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Address)]</div>
    }
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private bool _isValidating;

    private string ValidationClass(string field) =>
        _errors.ContainsKey(field) ? "is-invalid" : "";

    private async Task HandleNext()
    {
        _errors.Clear();

        if (string.IsNullOrWhiteSpace(FullName))
            _errors[nameof(FullName)] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors[nameof(Email)] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors[nameof(Phone)] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors[nameof(Address)] = "Address is required.";

        if (_errors.Count > 0) return;

        _isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                _errors[nameof(Email)] = "Please enter a valid email address.";
                return;
            }

            await FullNameChanged.InvokeAsync(FullName);
            await EmailChanged.InvokeAsync(Email);
            await PhoneChanged.InvokeAsync(Phone);
            await AddressChanged.InvokeAsync(Address);
            await OnNext.InvokeAsync();
        }
        finally
        {
            _isValidating = false;
        }
    }
}

@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = (string?)e.Value ?? "" })" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = (string?)e.Value ?? "" })" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           disabled="@(entry.IsCurrent)"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = string.IsNullOrEmpty((string?)e.Value) ? null : DateTime.Parse((string)e.Value) })" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" value="@entry.Description"
                          @onchange="e => UpdateEntry(index, entry with { Description = (string?)e.Value ?? "" })"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (_errors.Any())
{
    <div class="alert alert-danger">
        @foreach (var error in _errors)
        {
            <div>@error</div>
        }
    </div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _errors.Clear();
        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                _errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title))
                _errors.Add($"Position {i + 1}: Job title is required.");
            if (e.StartDate == default)
                _errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (_errors.Count == 0)
        {
            await OnNext.InvokeAsync();
        }
    }
}

@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Name"
                           @onchange="e => UpdateReference(index, reference with { Name = (string?)e.Value ?? "" })" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Relationship"
                           @onchange="e => UpdateReference(index, reference with { Relationship = (string?)e.Value ?? "" })" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@reference.Email"
                           @onchange="e => UpdateReference(index, reference with { Email = (string?)e.Value ?? "" })" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@reference.Phone"
                           @onchange="e => UpdateReference(index, reference with { Phone = (string?)e.Value ?? "" })" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (_errors.Any())
{
    <div class="alert alert-danger">
        @foreach (var error in _errors)
        {
            <div>@error</div>
        }
    </div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private void UpdateReference(int index, ReferenceModel updated)
    {
        References[index] = updated;
        ReferencesChanged.InvokeAsync(References);
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private async Task HandleNext()
    {
        _errors.Clear();
        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                _errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                _errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                _errors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone))
                _errors.Add($"Reference {i + 1}: Phone is required.");
        }

        if (_errors.Count == 0)
        {
            await OnNext.InvokeAsync();
        }
    }
}

@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter below</label>
    <textarea class="form-control" rows="12" maxlength="2000"
              @bind="CoverLetter" @bind:event="oninput"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / 2000 characters
    </div>
</div>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private async Task HandleNext()
    {
        _error = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            _error = "Cover letter is required.";
            return;
        }

        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">Review & Submit</h4>

@if (_submitted)
{
    <div class="alert alert-success text-center py-4">
        <h5>&#10003; Application Submitted Successfully!</h5>
        <p class="mb-0">Your application ID is: <strong>@_applicationId</strong></p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Full Name:</strong> @FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Email</div>
            </div>
            <div class="row mt-1">
                <div class="col-md-6"><strong>Phone:</strong> @Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-2 pb-2 border-bottom">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email &middot; @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="alert alert-danger">@_error</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_isSubmitting">
            @if (_isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
