    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _error;

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        _error = null;
        try
        {
            var personal = new PersonalInfo(FullName, Email, Phone, Address);
            var workHistory = new WorkHistory(
                WorkEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate,
