@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control @ValidationClass(nameof(FullName))" @bind="FullName" />
    @if (_errors.ContainsKey(nameof(FullName)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(FullName)]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @ValidationClass(nameof(Email))" @bind="Email" />
    @if (_errors.ContainsKey(nameof(Email)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Email)]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control @ValidationClass(nameof(Phone))" @bind="Phone" />
    @if (_errors.ContainsKey(nameof(Phone)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Phone)]</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control @ValidationClass(nameof(Address))" @bind="Address" rows="2"></textarea>
    @if (_errors.ContainsKey(nameof(Address)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Address)]</div>
    }
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private bool _isValidating;

    private string ValidationClass(string field) =>
        _errors.ContainsKey(field) ? "is-invalid" : "";

    private async Task HandleNext()
    {
        _errors.Clear();

        if (string.IsNullOrWhiteSpace(FullName))
            _errors[nameof(FullName)] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors[nameof(Email)] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors[nameof(Phone)] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors[nameof(Address)] = "Address is required.";

        if (_errors.Count > 0) return;

        _isValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                _errors[nameof(Email)] = "Please enter a valid email address.";
                return;
            }

            await FullNameChanged.InvokeAsync(FullName);
            await EmailChanged.InvokeAsync(Email);
            await PhoneChanged.InvokeAsync(Phone);
            await AddressChanged.InvokeAsync(Address);
            await OnNext.InvokeAsync();
        }
        finally
        {
            _isValidating = false;
        }
    }
}

