toolArgs.file_text:
@namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply

<h4 class="mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Name"
                           @onchange="e => UpdateReference(index, reference with { Name = (string?)e.Value ?? "" })" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Relationship"
                           @onchange="e => UpdateReference(index, reference with { Relationship = (string?)e.Value ?? "" })" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@reference.Email"
                           @onchange="e => UpdateReference(index, reference with { Email = (string?)e.Value ?? "" })" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@reference.Phone"
                           @onchange="e => UpdateReference(index, reference with { Phone = (string?)e.Value ?? "" })" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (_errors.Any())
{
    <div class="alert alert-danger">
        @foreach (var error in _errors)
        {
            <div>@error</div>
        }
    </div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private void UpdateReference(int index, ReferenceModel updated)
    {
        References[index] = updated;
        ReferencesChanged.InvokeAsync(References);
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private async Task HandleNext()
    {
        _errors.Clear();
        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                _errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                _errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                _errors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone))
                _errors.Add($"Reference {i + 1}: Phone is required.");
        }

        if (_errors.Count == 0)
        {
            await OnNext.InvokeAsync();
        }
    }
}

