namespace sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply;

public record WorkEntryModel
{
    public string Company { get; init; } = "";
    public string Title { get; init; } = "";
    public DateTime StartDate { get; init; } = DateTime.Today;
    public DateTime? EndDate { get; init; }
    public bool IsCurrent { get; init; }
    public string Description { get; init; } = "";
}

public record ReferenceModel
{
    public string Name { get; init; } = "";
    public string Relationship { get; init; } = "";
    public string Email { get; init; } = "";
    public string Phone { get; init; } = "";
}

@page "/apply"
@using sv_f536921da01f4da7af0d891a60feb7ee.Components.Pages.Apply
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" OnNavigateToStep="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep
                FullName="@_fullName" FullNameChanged="v => _fullName = v"
                Email="@_email" EmailChanged="v => _email = v"
                Phone="@_phone" PhoneChanged="v => _phone = v"
                Address="@_address" AddressChanged="v => _address = v"
                ApplicationService="ApplicationService"
                OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep
                Entries="_workEntries" EntriesChanged="v => _workEntries = v"
                OnNext="NextStep" OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep
                References="_references" ReferencesChanged="v => _references = v"
