@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> _errors = new();

    private static string FormatDate(DateTime date) => date.ToString("yyyy-MM-dd");
    private static string FormatNullableDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";

    private void SetEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void UpdateCompany(int index, ChangeEventArgs e) =>
        SetEntry(index, Entries[index] with { Company = (string?)e.Value ?? "" });

    private void UpdateTitle(int index, ChangeEventArgs e) =>
        SetEntry(index, Entries[index] with { Title = (string?)e.Value ?? "" });

    private void UpdateStartDate(int index, ChangeEventArgs e)
    {
        var val = (string?)e.Value ?? "";
        if (DateTime.TryParse(val, out var date))
            SetEntry(index, Entries[index] with { StartDate = date });
    }

    private void UpdateEndDate(int index, ChangeEventArgs e)
    {
        var val = (string?)e.Value ?? "";
        var endDate = string.IsNullOrEmpty(val) ? (DateTime?)null : DateTime.Parse(val);
        SetEntry(index, Entries[index] with { EndDate = endDate });
    }

    private void UpdateIsCurrent(int index, ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        SetEntry(index, Entries[index] with { IsCurrent = isCurrent, EndDate = isCurrent ? null : Entries[index].EndDate });
    }

    private void UpdateDescription(int index, ChangeEventArgs e) =>
        SetEntry(index, Entries[index] with { Description = (string?)e.Value ?? "" });

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _errors.Clear();
        for (int i = 0; i < Entries.Count; i++)
        {
            var entry = Entries[i];
            if (string.IsNullOrWhiteSpace(entry.Company))
                _errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                _errors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate == default)
                _errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (_errors.Count == 0)
        {
            await OnNext.InvokeAsync();
        }
    }
}

